from collections import defaultdict
from datetime import datetime
from openpyxl import load_workbook


def to_datetime(v):
    if isinstance(v, datetime):
        return datetime(v.year, v.month, v.day)
    if isinstance(v, str):
        v = v.strip()
        for fmt in ("%m/%d/%Y", "%m-%d-%Y", "%Y-%m-%d"):
            try:
                d = datetime.strptime(v, fmt)
                return datetime(d.year, d.month, d.day)
            except ValueError:
                pass
    return None


def read_ranges_sections(ws):
    sections = {}
    r = 1
    while r <= ws.max_row:
        title = ws.cell(r, 3).value
        if isinstance(title, str) and title.strip() and str(ws.cell(r + 1, 1).value).strip().upper() in {"S.N", "SN"}:
            name = title.strip().upper()
            data = []
            rr = r + 2
            while rr <= ws.max_row:
                if isinstance(ws.cell(rr, 3).value, str) and ws.cell(rr, 1).value is None and ws.cell(rr, 2).value is None:
                    break
                date_v = to_datetime(ws.cell(rr, 2).value)
                ref_v = ws.cell(rr, 4).value
                amt_v = ws.cell(rr, 5).value
                if date_v is not None and ref_v is not None and amt_v is not None:
                    data.append((date_v, str(ref_v).strip(), float(amt_v)))
                rr += 1
            sections[name] = data
            r = rr
        else:
            r += 1
    return sections


def locate_list_sections(ws):
    out = {}
    for r in range(1, ws.max_row + 1):
        title = ws.cell(r, 3).value
        if isinstance(title, str) and title.strip().upper() in {"STAGE", "DATA", "OPERATION"}:
            name = title.strip().upper()
            total_row = None
            for rr in range(r + 2, ws.max_row + 1):
                if str(ws.cell(rr, 1).value).strip().upper() == "TOTAL":
                    total_row = rr
                    break
            if total_row is not None:
                out[name] = (r + 2, total_row)
    return out


def aggregate_and_sort(rows):
    grouped = defaultdict(float)
    for d, ref, amt in rows:
        grouped[(d, ref)] += amt
    items = [(d, ref, amt) for (d, ref), amt in grouped.items()]
    items.sort(key=lambda x: (x[2], x[1], x[0]))
    return items


wb = load_workbook("uploads/ranges_lists.xlsx")
ws_ranges = wb["RANGES"]
ws_lists = wb["LISTS"]

ranges_sections = read_ranges_sections(ws_ranges)
list_sections = locate_list_sections(ws_lists)

for name, (data_start, total_row) in list_sections.items():
    rows = aggregate_and_sort(ranges_sections.get(name, []))
    data_end = total_row - 1

    for rr in range(data_start, total_row + 1):
        for cc in range(1, 5):
            ws_lists.cell(rr, cc).value = None

    capacity = data_end - data_start + 1
    for i, (d, ref, amt) in enumerate(rows[:capacity], start=0):
        rr = data_start + i
        ws_lists.cell(rr, 1).value = i + 1
        ws_lists.cell(rr, 2).value = d
        ws_lists.cell(rr, 3).value = ref
        ws_lists.cell(rr, 4).value = amt

        ws_lists.cell(rr, 1)._style = ws_lists.cell(3, 1)._style
        ws_lists.cell(rr, 2)._style = ws_lists.cell(3, 2)._style
        ws_lists.cell(rr, 3)._style = ws_lists.cell(3, 3)._style
        ws_lists.cell(rr, 4)._style = ws_lists.cell(3, 4)._style

    ws_lists.cell(total_row, 1).value = "TOTAL"
    ws_lists.cell(total_row, 4).value = f"=SUM(D{data_start}:D{data_end})"
    ws_lists.cell(total_row, 1)._style = ws_lists.cell(10, 1)._style
    ws_lists.cell(total_row, 4)._style = ws_lists.cell(10, 4)._style

wb.save("outputs/ranges_lists_result.xlsx")

print("sections", len(list_sections))
print("totals", len(list_sections))

